class Solution {
public:
    int countNumbers(string l, string r, int b) {
        long long res = 0, mod = 1e9 + 7;
        for (int i = l.length() - 1; i >= 0; i--) {
            int max_digit = r[i] - '0';
            int min_digit = l[i] - '0';
            for (int j = min_digit; j <= max_digit; j++) {
                if (j == 0 && i == 0) break;
                long long cur = 1;
                for (int k = 0; k < i; k++) {
                    cur = cur * b;
                }
                if (j == 0) cur = 1;
                else cur = cur * j;
                res = (res + cur) % mod;
            }
        }
        return res;
    }
};
